mapper.select:
SELECT *
FROM bookmark
WHERE company_email = #{companyEmail}
ORDER BY bookmarked_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM bookmark
WHERE company_email = #{companyEmail}

SELECT COUNT(*) > 0
FROM bookmark
WHERE company_email = #{companyEmail}
AND freelancer_email = #{freelancerEmail}

SELECT * FROM bookmark
WHERE company_email = #{companyEmail}
AND freelancer_email = #{freelancerEmail}
LIMIT 1

SELECT u.email, u.name, u.job_category AS jobCategory, u.profile_file_id AS profileFileId, u.created_at AS createdAt,
CASE WHEN b.bookmark_id IS NULL THEN FALSE ELSE TRUE END AS bookmarked
FROM user u
LEFT JOIN bookmark b ON b.freelancer_email = u.email AND b.company_email = #{companyEmail}
AND u.name LIKE CONCAT('%', #{keyword}, '%')
AND u.job_category = #{jobCategory}
AND b.bookmark_id IS NOT NULL
ORDER BY u.${sort} ${direction}
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM user u
LEFT JOIN bookmark b ON b.freelancer_email = u.email AND b.company_email = #{companyEmail}
AND u.name LIKE CONCAT('%', #{keyword}, '%')
AND u.job_category = #{jobCategory}
AND b.bookmark_id IS NOT NULL
